@StartSkit,全キャラ初期設定
// コンディションの初期化（時間指定）
@SetSkitCondition,auto,12:00:00,Fine

// コンディションの初期化（オート）
//@SetSkitCondition,auto,auto,Fine
// @SetSkitCondition,auto,auto,Fine
// @SetSkitCondition,04-01,auto,Rain
// @SetSkitCondition,auto,12:00:00,Fine

// カメラ位置の初期化
@SetSkitCamera,GL_S001_000,1,-1,-0.3

// 非登場キャストの非表示
@HideSkitCast,主人公
@HideSkitCast,彩葉
@HideSkitCast,紬
@HideSkitCast,凪
@HideSkitCast,花音
@HideSkitCast,スカーレット
@HideSkitCast,エステファニア
@HideSkitCast,ひまり子
@HideSkitCast,ロイズ
@HideSkitCast,配膳ロボ
@EndSkit


@StartSkit,全キャラ初期位置設定
// キャスト位置の初期化
@SetSkitCast,主人公,GL_R002_000,0,0,0,0
@SetSkitCast,彩葉,GL_R003_000,0,0,0,0
@SetSkitCast,花音,GL_R007_000,0,0,0,0
@SetSkitCast,凪,GL_R005_000,0,0,0,0
@SetSkitCast,紬,GL_R004_000,0,0,0,0
@SetSkitCast,スカーレット,GL_S001_000,0,0,35,0
@SetSkitCast,エステファニア,GL_R008_000,0,0,0,0
@SetSkitCast,ひまり子,GL_R009_000,0,0,0,0
@SetSkitCast,ロイズ,GL_S001_000,1,-1,-125,0
@SetSkitCast,配膳ロボ,GL_R014_001,1,1.4,-40,0
@EndSkit


@StartSkit,初期アクション設定
@PlaySkitCastAction,スカーレット,Action10
@ShowSkitCastMessage,スカーレット,斯卡蕾特
洛伊斯也要一起训练吗？
@WaitSkit,3.5
@PlaySkitCastAction,スカーレット,Action10
@PlaySkitCastAction,ロイズ,Action2
@EndSkit

@PlaySkit,全キャラ初期設定
@PlaySkit,全キャラ初期位置設定
@SetAfterSkit,初期アクション設定
